var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"쳇, 결국 본선 문턱만 밟아 보고 끝인가…….","JPN":"ちっ、結局本戦の入り口でさよならか……","ENG":"Tsk, we were this close to making it to the elimination round...","TWN":"嘖，結果離決賽還是只差臨門一腳嗎……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘이 아니라 다른 저격수였다면 달랐을 거예요.","JPN":"ノエルじゃなくて他のスナイパーだったら、違っていたはずだわ。","ENG":"If we had someone else as our sniper instead of Noelle, things would have been different.","TWN":"都是洛艾兒害的，換個狙擊手的話，結局肯定會不一樣。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"너무해요! 저도 최선을 다했는데……!","JPN":"ひどいです！　私も一生懸命頑張ったのに……！","ENG":"That's mean! I tried my best...!","TWN":"好過分！人家也很努力欸……！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"노엘, 내가 아는 식당에서 요리사를 구하고 있대. 네 적성은 용병이 아닌가 봐.","JPN":"ノエル、私の知ってるレストランでシェフを探してるんだって。あなたの適性は傭兵じゃないみたい。","ENG":"Noelle, a restaurant I know is looking for a chef. Maybe you're not fit to be a mercenary.","TWN":"洛艾兒，我知道有個餐廳正在招募廚師，你似乎不適合傭兵這個行業。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"계단에서 굴렀다고 기절해 있는 애는 펜릴 소대에 어울리지 않아.","JPN":"階段で転び落ちたくらいで気絶してる子は、フェンリル小隊に似合わない。","ENG":"Someone who's unconscious from falling down the stairs doesn't belong in Fenrir Squad.","TWN":"從樓梯上滾下來就暈倒的人，不適合待在芬里爾小隊。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그그그그그치만 워낙 갑작스러워서어어~!","JPN":"でででででも、本当に突然でしたから～！","ENG":"B-b-b-b-b-b-but it was all so sudden...!","TWN":"可是，可是，可是，那是因為太突然啦～！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"벌로 펜릴 소대 굿즈는 3개월 압수야.","JPN":"罰として、フェンリル小隊のグッズは3カ月間没収。","ENG":"All Fenrir Squad merch will be confiscated for the next 3 months.","TWN":"我要沒收你的芬里爾小隊周邊3個月！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"안 돼애애애애애애!","JPN":"ダメえええぇぇぇ！","ENG":"NOOOOOOOOOO!","TWN":"不可以～～～～～！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"노엘 양, 정신이 드나?","JPN":"ノエル君、気がついたかね？","ENG":"Noelle, are you okay?","TWN":"洛艾兒，你醒啦？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사장님! 굿즈를 압수당하면 저에게는 살아갈 의미가 없어요!","JPN":"社長！　グッズを没収されたら、私には生きていく意味なんてないんです！","ENG":"Boss! Without those merch, there's no meaning in life!","TWN":"老闆！要是沒收我的周邊，那我活著還有什麼意義！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"바즈라를 대신 드리겠습니다! 압수만은 제발 막아 주세요!","JPN":"代わりにヴァジュラをあげます！　没収だけは勘弁してください！","ENG":"I'll give you my vajra! Please, don't confiscate my merch!","TWN":"我把金剛杵給你！拜託不要沒收我的周邊！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아야! 바즈라가 왜 절 공격하는 거죠? 아얏! 흐잉!?","JPN":"痛っ！　どうしてヴァジュラが私を攻撃するんですか？　痛っ！　ふえん！？","ENG":"Ow! Why is my vajra attacking me? Ouch! Huh?!","TWN":"哎呀！金剛杵為什麼攻擊我？唉唷！嗚嗚！？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"자네가 헌신짝처럼 버려서?","JPN":"君が弊履のごとく捨ててしまったせいかね？","ENG":"Perhaps it's because you sold it off like it was worth nothing.","TWN":"因為你想把它當垃圾丟掉？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"울브즈베인이면 안 버렸을 텐데… 아얏! 농담이야!","JPN":"ウルブズベインだったら捨てなかったのに……いたた！　冗談だよ！","ENG":"If it was Wolvesbane, I wouldn't ha– Ow! I'm joking!","TWN":"要是狼之災禍的話我肯定不會丟掉的……唉唷！我開玩笑的啦！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"핫! 맞다! 펠리세트랑 라이카 씨는요?","JPN":"はっ！　そうだ！　フェリセットとライカさんは？","ENG":"Ah! Right! What happened to Félicette and Laika?","TWN":"對了！費莉塞特和萊卡呢？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아, 젠장…… 나이프에 너무 깊이 찔렸나.","JPN":"あ、くそ……ナイフで深く刺されちゃったかな。","ENG":"Ah, crap... I think my knife wound is too deep.","TWN":"呃，可惡……刀插得有點深。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"우리 여기 있어. 지금 위층에서 상대편과 대치 중이야.","JPN":"私たちはここにいるよ。今上の階で相手と対峙してるところ。","ENG":"Over here. We're upstairs, engaging with the enemy.","TWN":"我們在這裡，正在樓上和對方對峙中。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘, 다친 데는 없어요?","JPN":"ノエル、ケガはありませんか？","ENG":"Are you hurt, Noelle?","TWN":"洛艾兒，你沒受傷吧？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"전 쌩쌩해요! 방금 전에 바즈라한테 맞은 데가 제일 아픈 걸요!","JPN":"私は元気です！　さっきヴァジュラに殴られたところが一番痛いですから！","ENG":"I'm good, thanks! My vajra hurt the most, to be honest!","TWN":"我很好！只是剛被金剛杵打得有點痛！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그런데 나이프라니요? 설마 싸울 때도 반칙을 저지른 거예요?","JPN":"でも、ナイフって？　まさか、戦うときにも反則したんですか？","ENG":"What knife, though? Did they also cheat during combat?","TWN":"不過你剛說什麼刀？難道戰鬥時他們也有犯規嗎？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"넌 네가 왜 계단에서 굴러 떨어졌다고 생각하냐?","JPN":"あんた、なんで自分が階段から転げ落ちたと思ってるんだ？","ENG":"Why do you think you fell down the stairs?","TWN":"你覺得自己為什麼會從樓梯上滾下來?"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어두워서 발을 헛디뎌서요.","JPN":"暗いから足を踏み外して？","ENG":"Because it was dark and I tripped?","TWN":"因為太黑腳踩空啦。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……됐다, 얼빵아. 말을 말자.","JPN":"……もういい、間抜け。","ENG":"...Forget it, you goon. Just forget it.","TWN":"……算了，小瓜呆，當我沒問。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"노엘, 이쪽으로 합류할 수 있겠어요? 우리만으로는 화력이 부족해요.","JPN":"ノエル、こっちに合流できますか？　私たちだけでは火力が足りないんです。","ENG":"Noelle, do you think you can join us? We're falling back on firepower.","TWN":"洛艾兒，你能來跟我們會合嗎？光靠我們二個的火力不足。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그럼요!","JPN":"もちろんです！","ENG":"Sure!","TWN":"當然可以！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"기다리게. 더 좋은 방법이 있어.","JPN":"待ちたまえ。もっといい方法がある。","ENG":"Wait. I have a better plan.","TWN":"等等，我有更好的辦法。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네? 어떤 방법인데요?","JPN":"え？　どんな方法なんですか？","ENG":"What? What is it?","TWN":"嗯？什麼辦法？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"어서 얘기해 주세요, 코치. 더 오래 버티긴 어려울 거 같아요.","JPN":"早く話してください、コーチ。これ以上は持てなさそうです。","ENG":"Tell us now, Coach. We can't hold on for much longer.","TWN":"快說吧，教練，我們好像撐不了多久了。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"그 위치에서 바즈라만 조종해서 공격하는 게 어떤가?","JPN":"その位置で、ヴァジュラだけ操縦して攻撃するのはどうだ？","ENG":"Why don't you control your vajra and attack from where you're at now?","TWN":"在你現在的位置上操控金剛杵進行攻擊，怎麼樣？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"……앗.","JPN":"……あっ。","ENG":"...Ah.","TWN":"……喔。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그렇네요. 여기에는 상대편 사람이 한 명도 없어요!","JPN":"そうですね。こっちには相手が一人もいません！","ENG":"You're right. This place is completely empty!","TWN":"對吼，這裡連一個對方的人都沒有！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"마침 잘됐어요. 저격수에게는 최적의 위치네요.","JPN":"ちょうどよかったわ。スナイパーには最適の位置ですね。","ENG":"That's great news. It's the perfect spot for a sniper.","TWN":"那正好。對於狙擊手來說，那就是最好的位置。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"상대 팀도 조급해졌는지 우리만 노리기 바빠. 뒤통수가 훤하다고.","JPN":"相手チームも焦ってるせいか、私たちだけを狙ってる。後頭部丸見えだ。","ENG":"The enemy team is busy targeting us. They're getting impatient, which makes them vulnerable.","TWN":"對方好像也被逼急了，完全不敢輕舉妄動。現在他們處於劣勢。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"하, 하지만 안 보이는 곳에 있는 상대를 바즈라로 맞춰 본 적은 없는 걸요. 할 수 있을까요?","JPN":"で、でも見えないところにいる相手をヴァジュラで命中させたことはないんですけど。できるんでしょうか？","ENG":"B-but I've never shot anyone outside my vision before! Will I be able to do it?","TWN":"可，可是我從來沒用金剛杵打中過藏在暗處的對手，我辦得到嗎？"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"부담 가질 필요 없어, 노엘.","JPN":"難しく考える必要はないよ、ノエル。","ENG":"Don't stress over it, Noelle.","TWN":"不用有壓力，洛艾兒。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"시야는 우리 쪽에서 제공해 줄게. 너는 움직이는 데에만 집중하면 돼.","JPN":"視界はこっちから提供してあげる。あなたは動くことだけに集中すればいいよ。","ENG":"We'll provide you with visuals. You just focus on moving your weapon.","TWN":"我們會提供你視野。你只要專心操控就好。"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우, 우으…….","JPN":"う、うう……","ENG":"Uuh... Wahhh...","TWN":"唔，呃呃……"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"알겠습니다! 도전해 볼게요!","JPN":"わかりました！　挑戦してみます！","ENG":"Okay! Challenge accepted!","TWN":"好！挑戰！"},"stage":{"bg":"BASEMENT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};